  const msg = entry.messaging[0];
  const messageData = msg.message;

  // التحقق مما إذا كانت الرسالة تحتوي على ملحقات (Attachments)
  if (messageData && messageData.attachments) {
    const audioAttachment = messageData.attachments.find(att => att.type === 'audio');

    if (audioAttachment) {
      // إرجاع بيانات الرسالة الصوتية مع رابط الملف
      return [{ 
        json: { 
          event_type: "messenger_audio", 
          audio_url: audioAttachment.payload.url,
          sender_id: msg.sender.id,
          data: msg 
        } 
      }];
    }
  }

  // إذا كانت رسالة نصية عادية
  return [{ json: { event_type: "message", data: msg } }];
}

// 2. التعامل مع التفاعلات على المنشورات (Webhooks for Posts/Comments)
const change = entry.changes[0];
const value = change.value;

if (value.comment_id && value.item === "comment") {
  return [{ json: { event_type: "post_comment", data: value } }];
}

if (value.item === "reaction") {
  return [{ json: { event_type: "post_reaction", data: value } }];
}

if (value.verb === "add" && value.item === "post") {
  return [{ json: { event_type: "post_created", data: value } }];
}

if (value.verb === "edited") {
  return [{ json: { event_type: "post_edited", data: value } }];
}

if (value.verb === "remove") {
  return [{ json: { event_type: "post_deleted", data: value } }];
}

return [{ json: { event_type: "unknown", data: value } }];

