const body = items[0].json.body;
const entry = body.entry[0];

// 1. Handle Direct Messages (DMs)
if (entry.messaging) {
  const messaging = entry.messaging[0];

  // Optional: Skip "echoes" (messages sent by you/the bot) to prevent infinite loops
  if (messaging.message.attachments && messaging.message.attachments[0].type=="share") {
     return [{ json: { event_type: "share", data: messaging } }];
  }
  if (messaging.message && messaging.message.is_echo) {
     return [{ json: { event_type: "messages", data: messaging } }];
  }

  return [{ 
    json: { 
      event_type: "messages", 
      text: messaging.message?.text,
      sender_id: messaging.sender?.id,
      data: messaging 
    } 
  }];
}

// 2. Handle Comments
if (entry.changes) {
  const change = entry.changes[0];

  if (change.field === "comments") {
    return [{ 
      json: { 
        event_type: "comments", 
        text: change.value?.text,
        username: change.value?.from?.username,
        data: change.value 
      } 
    }];
  }
}

// 3. Fallback
return [{ json: { event_type: "unknown", data: entry } }];

return items.map(item => {
